import React from 'react';
import './Navbar.css';
import About from '../about/About';
import Research from '../research/Research';

import { NavLink, Route } from 'react-router-dom'
import { Nav, Navbar, NavDropdown} from 'react-bootstrap';


class Menu extends React.Component {

    activeLanguage = (language) => {
        switch(language) {
            case "0":
                //TODO traduzir para português
                document.getElementById("basic-nav-dropdown").textContent = "🇧🇷";
                break;
            case "1":
                //TODO translate to english
                document.getElementById("basic-nav-dropdown").textContent = "🇺🇸";
                break;
            case "2": 
                //TODO traducir para español
                document.getElementById("basic-nav-dropdown").textContent = "🇪🇸";
                break;
            case "3": 
                //Deutsche übersetzen
                document.getElementById("basic-nav-dropdown").textContent = "🇩🇪";
                break;
            default:
        }
    }

    dropdown = () => {
        return (
            <NavDropdown title="🇺🇸" id="basic-nav-dropdown" drop="left">
                <NavDropdown.Item eventKey="0" className="languages" onSelect={this.activeLanguage}>
                <span className="flag" role="img" aria-label="português">🇧🇷</span>
                    <span>Português</span>
                </NavDropdown.Item>
                <NavDropdown.Item  eventKey="1" className="languages" onSelect={this.activeLanguage}>
                <span className="flag" role="img" aria-label="english">🇺🇸</span>
                    <span>English</span>
                </NavDropdown.Item>
                <NavDropdown.Item  eventKey="2" className="languages" onSelect={this.activeLanguage}>
                <span className="flag" role="img" aria-label="español">🇪🇸</span>
                    <span>Español</span>
                </NavDropdown.Item>
                <NavDropdown.Item  eventKey="3" className="languages" onSelect={this.activeLanguage}>
                <span className="flag" role="img" aria-label="deutsche">🇩🇪</span>
                    <span>Deutsche</span>
                </NavDropdown.Item>
            </NavDropdown>
        )
    }

    render = () => {
        return (
            <div>
                <Navbar bg="dark" variant="dark" expand="lg">
                    <Navbar.Brand className="brand" href="/">
                        <span className="name">Nathan Gavenski</span>
                    </Navbar.Brand>
                    <Navbar.Toggle aria-controls="basic-navbar-nav" />
                    <Navbar.Collapse id="basic-navbar-nav">
                        <Nav className="ml-auto" onSelect={this.activeStatus}> 
                            {/* <Nav.Link as={NavLink} to="/resume">Resume</Nav.Link> */}
                            <Nav.Link as={NavLink} to="/" exact>About</Nav.Link>
                            <Nav.Link as={NavLink} to="/research">Research</Nav.Link>
                            {/* {this.dropdown()} */}
                        </Nav>
                    </Navbar.Collapse>
                </Navbar>
                <Route path="/" exact component={About} />
                <Route path="/research" component={Research} />
            </div>
        );
    }
}

export default Menu;
