import React from 'react';
import './Utils.css';

import { Row, Col } from 'react-bootstrap';

function sectionHeader(emoji, header, paragraph) {

    return (
        <Row className="sectionHeader">
            <Col xs={"auto"}>
                <h1>
                    <span className="emoji" role="img" aria-label={header}>{emoji}</span>
                </h1>
            </Col>
            <Col>
                <h1><span className="sectionTitle">{header}</span></h1>
                { !!paragraph && <p className="sectionSub">{paragraph}</p> }
            </Col>
        </Row>
    );

}

function pageHeader(emoji, header, paragraph) {

    return (
        <Row>
            <Col xs={"auto"}>
                <h1>
                    <span className="emoji" role="img" aria-label={header}>{emoji}</span>
                </h1>
            </Col>
            <Col>
                <h1><span className="pageTitle">{header}</span></h1>
                { !!paragraph && <h3 className="pageSub">{paragraph}</h3> }
            </Col>
        </Row>
    );

}

// TODO create a function to send bibtex to clipboard
function listSomething(l){
    const componentsList = l.map((entry, idx) => 
        <Row className="listEntry" key={idx}>
            <p className="listContent">
                { entry.authors } 
                <span className="entryName">{ entry.name }</span>
                { entry.place }
            </p>
            { !!entry.pdf && <a href={entry.pdf}>[PDF]</a> }
            { !!entry.bibtex && <a href={entry.bibtex}>[BibTex]</a> }
            { !!entry.github && <a href={entry.github}>[Github]</a> }
        </Row>
    );
    return componentsList;
}


export { sectionHeader, pageHeader, listSomething };